#include <iostream>
using namespace std;

class Rectangle {
private:
    int length, width;
public:
    Rectangle(int l, int w) {
        length = l;
        width = w;
    }
    int getArea() {
        return length * width;
    }
};

int main() {
    int l, w;
    cin >> l >> w;
    Rectangle rect(l, w);
    cout << rect.getArea();
    return 0;
}

